1	import { Request, Response, Router } from 'express';
2	import { ZodError } from 'zod';
3	import { requireAuth } from '../middleware/auth.middleware';
4	import { dashboardQuerySchema } from '../schemas/financial.schema';
5	import { getDashboard } from '../services/financial.service';
6	
7	export const financialRouter = Router();
8	
9	financialRouter.use(requireAuth);
10	
11	financialRouter.get('/dashboard', async (req: Request, res: Response) => {
12	  const authUser = req.authUser;
13	  if (!authUser) {
14	    res.status(401).json({ error: 'Authentication required' });
15	    return;
16	  }
17	
18	  try {
19	    const { month } = dashboardQuerySchema.parse(req.query);
20	    const result = await getDashboard({
21	      userId: authUser.id,
22	      month: month === undefined ? undefined : Number(month),
23	    });
24	    res.status(200).json(result);
25	  } catch (error) {
26	    if (error instanceof ZodError) {
27	      res.status(400).json({
28	        error: 'ValidationError',
29	        details: error.issues.map((issue) => ({
30	          field: issue.path.join('.'),
31	          message: issue.message,
32	        })),
33	      });
34	      return;
35	    }
36	
37	    console.error('Failed to compute financial dashboard', error);
38	    res.status(500).json({ error: 'Internal server error' });
39	  }
40	});
41

