1	import { HumanMessage, SystemMessage } from '@langchain/core/messages';
2	import { createChatModel } from './llm/chat-model';
3	import type {
4	  DiscretionaryItem,
5	  FinancialHealthRating,
6	  FinancialHealthSummary,
7	} from './financial.service';
8	
9	export interface RecommendationInput {
10	  health: FinancialHealthSummary;
11	  discretionaryItems: DiscretionaryItem[];
12	}
13	
14	export interface RecommendationPrompt {
15	  system: string;
16	  user: string;
17	}
18	
19	const TONE_GUIDANCE: Record<FinancialHealthRating, string> = {
20	  red: [
21	    'TONE: URGENT. The user cannot comfortably afford their debt repayments.',
22	    'Be direct and clear that change is needed now. Do not soften the message,',
23	    'but do not shame the user either. Focus on the largest, fastest cuts that',
24	    'will free up cash this month.',
25	  ].join(' '),
26	  amber: [
27	    'TONE: HONEST AND PRACTICAL. The user can afford their debts but has only a',
28	    'thin buffer. Recommend pragmatic trims that build a margin of safety,',
29	    'without alarming them.',
30	  ].join(' '),
31	  green: [
32	    'TONE: SUPPORTIVE AND MEASURED. The user has a comfortable buffer. Avoid',
33	    'urgency. Suggest small optimisations that could accelerate debt payoff,',
34	    'and acknowledge they are doing well.',
35	  ].join(' '),
36	};
37	
38	const SYSTEM_PROMPT_BASE = [
39	  'You are a financial wellbeing assistant helping a user manage their way out of debt.',
40	  "Your job: read the user's financial snapshot and produce 2–4 specific, actionable",
41	  'suggestions to change their DISCRETIONARY spending in order to accelerate debt repayment.',
42	  '',
43	  'Rules:',
44	  '- Ground every suggestion in the actual line items provided. Name them. Do not invent items.',
45	  '- Be SPECIFIC about how much money each suggestion would free up per month.',
46	  '- Never suggest cutting essentials or debt repayments — those are off-limits.',
47	  '- If the user has no discretionary spending, return an empty list.',
48	  '- Each suggestion must be a single short sentence (≤ 25 words). Plain text. No emojis.',
49	  '- Output STRICT JSON only, no prose, no markdown fences. Schema: {"recommendations": string[]}.',
50	].join('\n');
51	
52	export const buildRecommendationPrompt = (input: RecommendationInput): RecommendationPrompt => {
53	  const { health, discretionaryItems } = input;
54	
55	  const system = [SYSTEM_PROMPT_BASE, '', TONE_GUIDANCE[health.rating]].join('\n');
56	
57	  const ratingLabel = `${health.rating.toUpperCase()} (${ratingMeaning(health.rating)})`;
58	
59	  const itemsBlock =
60	    discretionaryItems.length === 0
61	      ? '(none — the user has no discretionary spending this month)'
62	      : discretionaryItems
63	          .map((item) => `- ${item.description}: £${item.amount.toFixed(2)}`)
64	          .join('\n');
65	
66	  const user = [
67	    `Financial health rating: ${ratingLabel}`,
68	    `Income this month: £${health.income.toFixed(2)}`,
69	    `Essential spend: £${health.essentialSpend.toFixed(2)}`,
70	    `Debt repayments: £${health.debtRepayments.toFixed(2)}`,
71	    `Discretionary spend: £${health.discretionarySpend.toFixed(2)}`,
72	    `Surplus after essentials: £${health.surplusAfterEssentials.toFixed(2)}`,
73	    `Headroom (after debt): £${health.headroom.toFixed(2)} (${(health.headroomRatio * 100).toFixed(1)}% of income)`,
74	    '',
75	    'Discretionary line items:',
76	    itemsBlock,
77	    '',
78	    'Return JSON only.',
79	  ].join('\n');
80	
81	  return { system, user };
82	};
83	
84	const ratingMeaning = (rating: FinancialHealthRating): string => {
85	  switch (rating) {
86	    case 'red':
87	      return 'cannot comfortably afford debt repayments';
88	    case 'amber':
89	      return 'manageable but limited buffer';
90	    case 'green':
91	      return 'comfortable, meaningful buffer';
92	  }
93	};
94	
95	// The LLM is instructed to reply with JSON only, but real models occasionally
96	// wrap output in markdown fences or leading prose. Strip the obvious patterns
97	// before parsing, and fall back to an empty list rather than failing the whole
98	// dashboard endpoint if the model misbehaves.
99	const parseRecommendations = (raw: string): string[] => {
100	  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
101	  const candidate = (fenced ? fenced[1] : raw).trim();
102	  try {
103	    const parsed: unknown = JSON.parse(candidate);
104	    if (
105	      parsed &&
106	      typeof parsed === 'object' &&
107	      'recommendations' in parsed &&
108	      Array.isArray((parsed as { recommendations: unknown }).recommendations)
109	    ) {
110	      return (parsed as { recommendations: unknown[] }).recommendations
111	        .filter((r): r is string => typeof r === 'string' && r.trim().length > 0)
112	        .map((r) => r.trim());
113	    }
114	  } catch {
115	    // fall through
116	  }
117	  return [];
118	};
119	
120	const extractText = (content: unknown): string => {
121	  if (typeof content === 'string') return content;
122	  if (Array.isArray(content)) {
123	    return content
124	      .map((part) => {
125	        if (typeof part === 'string') return part;
126	        if (part && typeof part === 'object' && 'text' in part) {
127	          const text = (part as { text: unknown }).text;
128	          return typeof text === 'string' ? text : '';
129	        }
130	        return '';
131	      })
132	      .join('');
133	  }
134	  return '';
135	};
136	
137	export const getRecommendations = async (input: RecommendationInput): Promise<string[]> => {
138	  // No discretionary items → no negotiable spend to talk about. Skip the LLM
139	  // call entirely so we don't pay for a request that has nothing to recommend.
140	  if (input.discretionaryItems.length === 0) {
141	    return [];
142	  }
143	
144	  const prompt = buildRecommendationPrompt(input);
145	  const model = createChatModel();
146	  const response = await model.invoke([
147	    new SystemMessage(prompt.system),
148	    new HumanMessage(prompt.user),
149	  ]);
150	
151	  return parseRecommendations(extractText(response.content));
152	};

