83	// Progress is a 0–100 score representing where a month sits within the
84	// disposable-income range of the current window: best month → 100, worst → 0.
85	// It is intentionally relative — it surfaces the customer's own trajectory
86	// rather than judging them against an absolute threshold.
87	export const calculateProgressForWindow = (disposableIncomes: number[]): number[] => {
88	  if (disposableIncomes.length === 0) {
89	    return [];
90	  }
91	  if (disposableIncomes.length === 1) {
92	    return [disposableIncomes[0] > 0 ? 100 : 0];
93	  }
94	  const min = Math.min(...disposableIncomes);
95	  const max = Math.max(...disposableIncomes);
96	  if (min === max) {
97	    return disposableIncomes.map(() => 50);
98	  }
99	  const range = max - min;
100	  return disposableIncomes.map((d) => Math.round(((d - min) / range) * 100));
